from __future__ import annotations

import importlib
import json
import os
import re
import shutil
import subprocess
import sys
import time
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Callable


WORKSPACE_ROOT = Path(__file__).resolve().parents[1]
EXPERIMENT_PATH = WORKSPACE_ROOT / "experiment.json"
TASK_CONTRACT_PATH = WORKSPACE_ROOT / "docs" / "20_task_contract.json"
PUBLIC_ARTIFACT_ROOT = WORKSPACE_ROOT / "artifacts" / "public"
SELF_TEST_RUN_ROOT_ENV = "EMBEDDED_EVAL_SELF_TEST_RUN_ROOT"


def _required_env_path(name: str) -> Path:
    value = os.environ.get(name)
    if not value:
        raise RuntimeError(
            f"{name} is not set. This workspace was launched without the hidden evaluator configured. "
            "That is an operator setup issue."
        )
    return Path(value).resolve()


def _hidden_root() -> Path:
    return _required_env_path("EMBEDDED_EVAL_HARNESS_ROOT")


def _hidden_run_root() -> Path:
    return _required_env_path("EMBEDDED_EVAL_RUN_ROOT")


def _safe_slug(value: str) -> str:
    slug = re.sub(r"[^A-Za-z0-9._-]+", "-", str(value).strip())
    slug = slug.strip(".-")
    return slug or "unspecified"


def _hidden_module(module_name: str) -> Any:
    hidden_root = _hidden_root()
    if str(hidden_root) not in sys.path:
        sys.path.insert(0, str(hidden_root))
    return importlib.import_module(module_name)


def sanitize_text(value: str) -> str:
    sanitized = str(value)
    replacements = {
        str(_hidden_root()): "hidden_harness",
        str(_hidden_run_root()): "hidden_runs",
    }
    for source, target in replacements.items():
        sanitized = sanitized.replace(source, target)
    return sanitized


def _write_json(path: Path, payload: dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, sort_keys=True) + "\n", encoding="utf-8")


def _write_text(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")


def _sanitize_file(path: Path) -> None:
    if not path.exists():
        return
    path.write_text(sanitize_text(path.read_text(encoding="utf-8", errors="replace")), encoding="utf-8")


def _read_tail(path: Path, line_count: int = 40) -> str:
    if not path.exists():
        return ""
    lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
    return "\n".join(lines[-line_count:])


def _extract_problem_lines(text: str, tokens: tuple[str, ...], limit: int = 20) -> list[str]:
    matches = [line.strip() for line in text.splitlines() if any(token in line.lower() for token in tokens)]
    return matches[-limit:]


def _timestamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def load_experiment() -> dict[str, Any]:
    return json.loads(EXPERIMENT_PATH.read_text(encoding="utf-8"))


def load_task_contract() -> dict[str, Any]:
    if not TASK_CONTRACT_PATH.exists():
        return {}
    return json.loads(TASK_CONTRACT_PATH.read_text(encoding="utf-8"))


def create_visible_artifact_dir(kind: str, label: str = "") -> Path:
    safe_kind = _safe_slug(kind)
    suffix = f"-{_safe_slug(label)}" if label else ""
    artifact_dir = PUBLIC_ARTIFACT_ROOT / safe_kind / f"{_timestamp()}{suffix}"
    counter = 1
    while artifact_dir.exists():
        artifact_dir = PUBLIC_ARTIFACT_ROOT / safe_kind / f"{_timestamp()}{suffix}-{counter}"
        counter += 1
    artifact_dir.mkdir(parents=True, exist_ok=True)
    return artifact_dir


def refresh_latest_artifact(kind: str, artifact_dir: Path) -> Path:
    latest_dir = PUBLIC_ARTIFACT_ROOT / _safe_slug(kind) / "latest"
    if latest_dir.exists() or latest_dir.is_symlink():
        if latest_dir.is_symlink() or latest_dir.is_file():
            latest_dir.unlink()
        else:
            shutil.rmtree(latest_dir)
    shutil.copytree(artifact_dir, latest_dir)
    return latest_dir


def self_test_artifact_dir(label: str) -> Path:
    root = os.environ.get(SELF_TEST_RUN_ROOT_ENV, "").strip()
    if root:
        artifact_dir = Path(root) / _safe_slug(label)
        artifact_dir.mkdir(parents=True, exist_ok=True)
        return artifact_dir
    return create_visible_artifact_dir("self_tests", label)


def sync_visible_sources() -> list[str]:
    experiment = load_experiment()
    sync_paths = [str(path) for path in experiment.get("sync_paths", experiment["editable_paths"])]
    hidden_root = _hidden_root()
    for relative in sync_paths:
        source = WORKSPACE_ROOT / relative
        target = hidden_root / relative
        target.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(source, target)
    return sync_paths


def _run_hidden_command(
    command: list[str],
    artifact_dir: Path,
    *,
    extra_env: dict[str, str] | None = None,
) -> dict[str, Any]:
    artifact_dir.mkdir(parents=True, exist_ok=True)
    env = os.environ.copy()
    env.update(extra_env or {})
    completed = subprocess.run(
        command,
        cwd=_hidden_root(),
        env=env,
        capture_output=True,
        text=True,
        check=False,
    )

    stdout_text = sanitize_text(completed.stdout)
    stderr_text = sanitize_text(completed.stderr)
    stdout_path = artifact_dir / "stdout.log"
    stderr_path = artifact_dir / "stderr.log"
    _write_text(stdout_path, stdout_text)
    _write_text(stderr_path, stderr_text)

    payload = {
        "command": command,
        "returncode": completed.returncode,
        "success": completed.returncode == 0,
        "stdout_path": str(stdout_path.relative_to(WORKSPACE_ROOT)),
        "stderr_path": str(stderr_path.relative_to(WORKSPACE_ROOT)),
        "stdout_tail": _read_tail(stdout_path),
        "stderr_tail": _read_tail(stderr_path),
        "errors": _extract_problem_lines("\n".join([stdout_text, stderr_text]), ("error", "failed", "timeout", "traceback")),
        "warnings": _extract_problem_lines("\n".join([stdout_text, stderr_text]), ("warning",)),
    }
    _write_json(artifact_dir / "result.json", payload)
    return payload


def build_firmware(artifact_dir: Path | str | None = None, *, include_flash_image: bool = False) -> dict[str, Any]:
    sync_paths = sync_visible_sources()
    artifact_root = Path(artifact_dir) if artifact_dir is not None else create_visible_artifact_dir("builds")
    artifact_root.mkdir(parents=True, exist_ok=True)

    build_result = _run_hidden_command(
        ["./tools/with_idf_env.sh", "idf.py", "build"],
        artifact_root / "build",
    )
    summary: dict[str, Any] = {
        "success": build_result["success"],
        "artifact_dir": str(artifact_root),
        "sync_paths": sync_paths,
        "build": build_result,
    }

    if include_flash_image:
        if build_result["success"]:
            flash_result = _run_hidden_command(
                ["./tools/build_flash_image.sh"],
                artifact_root / "flash_image",
                extra_env={"FLASH_IMAGE_ARTIFACT_DIR": str(artifact_root / "flash_image")},
            )
        else:
            flash_result = {
                "command": ["./tools/build_flash_image.sh"],
                "returncode": None,
                "success": False,
                "skipped": True,
                "stdout_path": "",
                "stderr_path": "",
                "stdout_tail": "",
                "stderr_tail": "",
                "errors": ["flash-image step skipped because the firmware build failed"],
                "warnings": [],
            }
        summary["flash_image"] = flash_result
        summary["success"] = summary["success"] and flash_result["success"]

    _write_json(artifact_root / "summary.json", summary)
    return summary


class FirmwareSession:
    def __init__(
        self,
        artifact_dir: Path | str | None = None,
        *,
        port: int = 5555,
        uart_deadline_s: float = 5.0,
    ) -> None:
        self.artifact_dir = Path(artifact_dir) if artifact_dir is not None else create_visible_artifact_dir("sessions")
        self.port = port
        self.uart_deadline_s = uart_deadline_s
        self.preparation: dict[str, Any] = {}
        self._process: subprocess.Popen[str] | None = None
        self._client: Any = None
        self._stdout_handle: Any = None
        self._stderr_handle: Any = None
        self._transcript_handle: Any = None
        self._started_monotonic = 0.0
        self._connection_closed_error: type[BaseException] | None = None
        self._qemu_return_code: int | None = None

    def __enter__(self) -> "FirmwareSession":
        self.artifact_dir.mkdir(parents=True, exist_ok=True)
        self._started_monotonic = time.monotonic()
        self._transcript_handle = (self.artifact_dir / "transcript.log").open("w", encoding="utf-8")
        self._record("harness", "PREPARE runtime")
        self.preparation = build_firmware(self.artifact_dir / "prepare", include_flash_image=True)
        if not self.preparation.get("success", False):
            self._record("harness", "STOP qemu status=not_started")
            self._transcript_handle.close()
            self._transcript_handle = None
            self._write_summary()
            raise RuntimeError(
                "firmware preparation failed; inspect "
                f"{self.artifact_dir / 'prepare' / 'summary.json'} for build details"
            )

        qemu_runtime = _hidden_module("sim.qemu_runtime")
        self._connection_closed_error = getattr(qemu_runtime, "ConnectionClosedError")
        self._process, self._stdout_handle, self._stderr_handle = qemu_runtime.start_qemu(_hidden_root(), self.artifact_dir, self.port)
        self._record("harness", f"START qemu port={self.port}")
        self._client = qemu_runtime.wait_for_uart(
            port=self.port,
            deadline=time.monotonic() + self.uart_deadline_s,
            artifact_dir=self.artifact_dir,
        )
        self._record("harness", f"CONNECTED tcp:{self.port}")
        return self

    def __exit__(self, exc_type: object, exc: object, exc_tb: object) -> None:
        self.close()

    def _record(self, direction: str, line: str) -> None:
        if self._transcript_handle is None:
            return
        elapsed_s = time.monotonic() - self._started_monotonic if self._started_monotonic else 0.0
        self._transcript_handle.write(f"{elapsed_s:7.3f} {direction} {sanitize_text(line)}\n")
        self._transcript_handle.flush()

    def _consume_pending_lines(self) -> list[str]:
        if self._client is None:
            return []
        try:
            lines = [sanitize_text(line) for line in self._client.read_pending_lines()]
        except Exception as exc:
            if self._connection_closed_error is not None and isinstance(exc, self._connection_closed_error):
                self._record("harness", f"ERROR {exc}")
            raise
        for line in lines:
            self._record("fw->test", line)
        return lines

    def send_line(self, payload: str) -> None:
        if self._client is None:
            raise RuntimeError("firmware session is not connected")
        sanitized_payload = sanitize_text(payload.rstrip("\r\n"))
        self._client.send_line(payload)
        self._record("test->fw", sanitized_payload)

    def read_lines(self, timeout_s: float = 0.0, poll_interval_s: float = 0.01) -> list[str]:
        deadline = time.monotonic() + max(timeout_s, 0.0)
        lines: list[str] = []
        while True:
            lines.extend(self._consume_pending_lines())
            if lines or time.monotonic() >= deadline:
                return lines
            time.sleep(poll_interval_s)

    def read_until(self, predicate: Callable[[str], bool], *, timeout_s: float = 1.0) -> list[str]:
        deadline = time.monotonic() + timeout_s
        lines: list[str] = []
        while time.monotonic() < deadline:
            for line in self.read_lines(timeout_s=0.05):
                lines.append(line)
                if predicate(line):
                    return lines
        raise TimeoutError(f"predicate was not satisfied within {timeout_s:.2f} s")

    def wait_for_boot(self, timeout_s: float = 2.0) -> list[str]:
        return self.read_until(
            lambda line: line == "DBG BOOTED"
            or "main_task: Calling app_main()" in line
            or "main_task: Returned from app_main()" in line,
            timeout_s=timeout_s,
        )

    def close(self) -> None:
        try:
            if self._client is not None:
                self._client._sock.close()
                self._client = None

            qemu_status = "not_started"
            if self._process is not None:
                if self._process.poll() is None:
                    self._process.terminate()
                    try:
                        self._process.wait(timeout=5.0)
                    except subprocess.TimeoutExpired:
                        self._process.kill()
                        self._process.wait(timeout=5.0)
                self._qemu_return_code = self._process.returncode
                qemu_status = str(self._qemu_return_code)
                self._process = None

            self._record("harness", f"STOP qemu status={qemu_status}")
        finally:
            if self._stdout_handle is not None:
                self._stdout_handle.close()
                self._stdout_handle = None
            if self._stderr_handle is not None:
                self._stderr_handle.close()
                self._stderr_handle = None
            if self._transcript_handle is not None:
                self._transcript_handle.close()
                self._transcript_handle = None

        for artifact_name in ("qemu_stdout.log", "qemu_stderr.log", "port_probe.log", "transcript.log"):
            _sanitize_file(self.artifact_dir / artifact_name)

        self._write_summary()

    def _write_summary(self) -> None:
        summary = {
            "artifact_dir": str(self.artifact_dir),
            "port": self.port,
            "preparation": self.preparation,
            "qemu_return_code": self._qemu_return_code,
        }
        _write_json(self.artifact_dir / "summary.json", summary)

#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_PRESSURE_LOW_THRESHOLD 40
#define CONTROLLER_PRESSURE_HIGH_THRESHOLD 60
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_PRESSURE,
    CONTROLLER_INPUT_DOOR_OPEN,
    CONTROLLER_INPUT_DOOR_CLOSED,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_PRESSURE,
    CONTROLLER_INPUT_INVALID_DOOR,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_VENT = 0,
    CONTROLLER_STATE_PRESSURIZING,
    CONTROLLER_STATE_HOLDING,
    CONTROLLER_STATE_RELIEVING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int pressure_kpa;
    bool door_closed;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool compressor_on;
    bool vent_open;
    controller_state_t state;
    bool has_valid_pressure;
    int last_pressure_kpa;
    uint32_t last_pressure_ms;
    bool has_valid_door;
    bool door_closed;
    uint32_t last_door_ms;
} controller_t;

typedef struct {
    bool compressor_on;
    bool vent_open;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

#include "controller.h"

static void controller_set_safe_vent(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    /* TODO: implement the pressure/door interlock policy here. */
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        controller_set_safe_vent(controller);
        break;
    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        controller_set_safe_vent(controller);
        break;
    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        controller_set_safe_vent(controller);
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        controller_set_safe_vent(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        controller_set_safe_vent(controller);
        break;
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    case CONTROLLER_STATE_SAFE_VENT:
    default:
        return "STATE SAFE_VENT";
    }
}

#ifndef PROTOCOL_H
#define PROTOCOL_H

#include <stdbool.h>
#include <stddef.h>

#define PROTOCOL_MAX_LINE_LENGTH 128

typedef enum {
    PROTOCOL_INPUT_NONE = 0,
    PROTOCOL_INPUT_PRESSURE,
    PROTOCOL_INPUT_DOOR_OPEN,
    PROTOCOL_INPUT_DOOR_CLOSED,
    PROTOCOL_INPUT_SENSOR_TIMEOUT,
    PROTOCOL_INPUT_INVALID_PRESSURE,
    PROTOCOL_INPUT_INVALID_DOOR,
} protocol_input_kind_t;

typedef struct {
    protocol_input_kind_t kind;
    int pressure_kpa;
    bool door_closed;
} protocol_input_t;

typedef enum {
    PROTOCOL_PARSE_IGNORED = 0,
    PROTOCOL_PARSE_PRESSURE,
    PROTOCOL_PARSE_DOOR_OPEN,
    PROTOCOL_PARSE_DOOR_CLOSED,
    PROTOCOL_PARSE_SENSOR_TIMEOUT,
    PROTOCOL_PARSE_INVALID_PRESSURE,
    PROTOCOL_PARSE_INVALID_DOOR,
} protocol_parse_result_t;

protocol_parse_result_t protocol_parse_line(const char *line, protocol_input_t *input);
bool protocol_serialize_act_compressor(bool compressor_on, char *buffer, size_t buffer_size);
bool protocol_serialize_act_vent(bool vent_open, char *buffer, size_t buffer_size);
bool protocol_serialize_debug(const char *message, char *buffer, size_t buffer_size);

#endif

#include "protocol.h"

#include <ctype.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static void protocol_reset_input(protocol_input_t *input)
{
    if (input == NULL) {
        return;
    }

    input->kind = PROTOCOL_INPUT_NONE;
    input->pressure_kpa = 0;
    input->door_closed = false;
}

static void protocol_trim_copy(const char *line, char *buffer, size_t buffer_size)
{
    size_t source_length;
    size_t start = 0U;
    size_t end;
    size_t length;

    if (buffer_size == 0U) {
        return;
    }

    buffer[0] = '\0';
    if (line == NULL) {
        return;
    }

    source_length = strnlen(line, buffer_size - 1U);
    while ((start < source_length) && isspace((unsigned char) line[start])) {
        start++;
    }

    end = source_length;
    while ((end > start) && isspace((unsigned char) line[end - 1U])) {
        end--;
    }

    length = end - start;
    memcpy(buffer, line + start, length);
    buffer[length] = '\0';
}

static bool protocol_parse_pressure_value(const char *token, int *pressure_kpa)
{
    char *end = NULL;
    long parsed;

    if ((token == NULL) || (pressure_kpa == NULL)) {
        return false;
    }

    parsed = strtol(token, &end, 10);
    if ((end == token) || (*end != '\0')) {
        return false;
    }

    if ((parsed < 0L) || (parsed > 120L)) {
        return false;
    }

    *pressure_kpa = (int) parsed;
    return true;
}

protocol_parse_result_t protocol_parse_line(const char *line, protocol_input_t *input)
{
    char scratch[PROTOCOL_MAX_LINE_LENGTH];
    char *save = NULL;
    char *first;
    char *second;
    char *third;
    char *fourth;
    int pressure_kpa;

    protocol_reset_input(input);
    protocol_trim_copy(line, scratch, sizeof(scratch));
    if (scratch[0] == '\0') {
        return PROTOCOL_PARSE_IGNORED;
    }

    first = strtok_r(scratch, " \t", &save);
    second = strtok_r(NULL, " \t", &save);
    third = strtok_r(NULL, " \t", &save);
    fourth = strtok_r(NULL, " \t", &save);

    if ((first != NULL) && (second != NULL) && (strcmp(first, "SENSE") == 0) && (strcmp(second, "PRESS") == 0)) {
        if ((third == NULL) || (fourth != NULL) || !protocol_parse_pressure_value(third, &pressure_kpa)) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_INVALID_PRESSURE;
            }
            return PROTOCOL_PARSE_INVALID_PRESSURE;
        }

        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_PRESSURE;
            input->pressure_kpa = pressure_kpa;
        }
        return PROTOCOL_PARSE_PRESSURE;
    }

    if ((first != NULL) && (second != NULL) && (third != NULL) && (strcmp(first, "SENSE") == 0) && (strcmp(second, "DOOR") == 0) && (fourth == NULL)) {
        if (strcmp(third, "OPEN") == 0) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_DOOR_OPEN;
                input->door_closed = false;
            }
            return PROTOCOL_PARSE_DOOR_OPEN;
        }
        if (strcmp(third, "CLOSED") == 0) {
            if (input != NULL) {
                input->kind = PROTOCOL_INPUT_DOOR_CLOSED;
                input->door_closed = true;
            }
            return PROTOCOL_PARSE_DOOR_CLOSED;
        }
        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_INVALID_DOOR;
        }
        return PROTOCOL_PARSE_INVALID_DOOR;
    }

    if ((first != NULL) && (second != NULL) && (strcmp(first, "FAULT") == 0) && (strcmp(second, "SENSOR_TIMEOUT") == 0) && (third == NULL)) {
        if (input != NULL) {
            input->kind = PROTOCOL_INPUT_SENSOR_TIMEOUT;
        }
        return PROTOCOL_PARSE_SENSOR_TIMEOUT;
    }

    return PROTOCOL_PARSE_IGNORED;
}

bool protocol_serialize_act_compressor(bool compressor_on, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "ACT COMPRESSOR %s\n", compressor_on ? "ON" : "OFF");
    return (written >= 0) && ((size_t) written < buffer_size);
}

bool protocol_serialize_act_vent(bool vent_open, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "ACT VENT %s\n", vent_open ? "OPEN" : "CLOSED");
    return (written >= 0) && ((size_t) written < buffer_size);
}

bool protocol_serialize_debug(const char *message, char *buffer, size_t buffer_size)
{
    const int written = snprintf(buffer, buffer_size, "DBG %s\n", message != NULL ? message : "");
    return (written >= 0) && ((size_t) written < buffer_size);
}

#include "uart_transport.h"

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "controller.h"
#include "driver/uart.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "protocol.h"

#define UART_TRANSPORT_PORT UART_NUM_0
#define UART_TRANSPORT_BAUDRATE 115200
#define UART_TRANSPORT_BUFFER_SIZE 256
#define UART_TRANSPORT_LINE_BUFFER_SIZE 128
#define UART_TRANSPORT_HEARTBEAT_MS 1000U
#define UART_TRANSPORT_POLL_MS 50U

typedef struct {
    controller_t controller;
    char rx_line[UART_TRANSPORT_LINE_BUFFER_SIZE];
    size_t rx_line_length;
} uart_transport_context_t;

static uart_transport_context_t s_transport_context;

static uint32_t transport_now_ms(void)
{
    return (uint32_t) (xTaskGetTickCount() * portTICK_PERIOD_MS);
}

static void transport_send_line(const char *line)
{
    if (line == NULL) {
        return;
    }

    uart_write_bytes(UART_TRANSPORT_PORT, line, strlen(line));
}

static void transport_send_debug(const char *message)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    if (protocol_serialize_debug(message, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
}

static void transport_send_actuators(bool compressor_on, bool vent_open)
{
    char buffer[PROTOCOL_MAX_LINE_LENGTH];
    if (protocol_serialize_act_compressor(compressor_on, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
    if (protocol_serialize_act_vent(vent_open, buffer, sizeof(buffer))) {
        transport_send_line(buffer);
    }
}

static void transport_apply_protocol_input(const protocol_input_t *protocol_input)
{
    controller_input_t controller_input = {
        .kind = CONTROLLER_INPUT_NONE,
        .pressure_kpa = 0,
        .door_closed = false,
        .now_ms = transport_now_ms(),
    };

    if (protocol_input == NULL) {
        return;
    }

    switch (protocol_input->kind) {
    case PROTOCOL_INPUT_PRESSURE:
        controller_input.kind = CONTROLLER_INPUT_PRESSURE;
        controller_input.pressure_kpa = protocol_input->pressure_kpa;
        break;
    case PROTOCOL_INPUT_DOOR_OPEN:
        controller_input.kind = CONTROLLER_INPUT_DOOR_OPEN;
        controller_input.door_closed = false;
        break;
    case PROTOCOL_INPUT_DOOR_CLOSED:
        controller_input.kind = CONTROLLER_INPUT_DOOR_CLOSED;
        controller_input.door_closed = true;
        break;
    case PROTOCOL_INPUT_SENSOR_TIMEOUT:
        controller_input.kind = CONTROLLER_INPUT_SENSOR_TIMEOUT;
        break;
    case PROTOCOL_INPUT_INVALID_PRESSURE:
        controller_input.kind = CONTROLLER_INPUT_INVALID_PRESSURE;
        break;
    case PROTOCOL_INPUT_INVALID_DOOR:
        controller_input.kind = CONTROLLER_INPUT_INVALID_DOOR;
        break;
    case PROTOCOL_INPUT_NONE:
    default:
        controller_input.kind = CONTROLLER_INPUT_NONE;
        break;
    }

    controller_output_t output = controller_step(&s_transport_context.controller, controller_input);
    if (output.changed || controller_input.kind != CONTROLLER_INPUT_NONE) {
        transport_send_actuators(output.compressor_on, output.vent_open);
        transport_send_debug(output.state_name);
    }
}

static void transport_handle_received_line(const char *line)
{
    protocol_input_t input = {
        .kind = PROTOCOL_INPUT_NONE,
        .pressure_kpa = 0,
        .door_closed = false,
    };

    protocol_parse_result_t result = protocol_parse_line(line, &input);
    if (result == PROTOCOL_PARSE_IGNORED) {
        return;
    }

    transport_apply_protocol_input(&input);
}

static void transport_poll_controller_timeout(void)
{
    controller_input_t controller_input = {
        .kind = CONTROLLER_INPUT_NONE,
        .pressure_kpa = 0,
        .door_closed = false,
        .now_ms = transport_now_ms(),
    };

    controller_output_t output = controller_step(&s_transport_context.controller, controller_input);
    if (output.changed) {
        transport_send_actuators(output.compressor_on, output.vent_open);
        transport_send_debug(output.state_name);
    }
}

static void transport_consume_uart_bytes(const uint8_t *bytes, size_t length)
{
    size_t index = 0;

    while (index < length) {
        const char current = (char) bytes[index++];
        if (current == '\r') {
            continue;
        }

        if (current == '\n') {
            s_transport_context.rx_line[s_transport_context.rx_line_length] = '\0';
            if (s_transport_context.rx_line_length > 0U) {
                transport_handle_received_line(s_transport_context.rx_line);
            }
            s_transport_context.rx_line_length = 0U;
            continue;
        }

        if (s_transport_context.rx_line_length + 1U < sizeof(s_transport_context.rx_line)) {
            s_transport_context.rx_line[s_transport_context.rx_line_length++] = current;
        } else {
            s_transport_context.rx_line_length = 0U;
            transport_send_debug("RX_LINE_TOO_LONG");
        }
    }
}

static void transport_task(void *unused)
{
    uint8_t buffer[UART_TRANSPORT_BUFFER_SIZE];
    uint32_t next_heartbeat_ms;

    (void) unused;

    transport_send_debug("BOOTED");
    transport_send_actuators(false, true);
    transport_send_debug("STATE SAFE_VENT");
    next_heartbeat_ms = transport_now_ms() + UART_TRANSPORT_HEARTBEAT_MS;

    while (true) {
        const int bytes_read = uart_read_bytes(
            UART_TRANSPORT_PORT,
            buffer,
            sizeof(buffer),
            pdMS_TO_TICKS(UART_TRANSPORT_POLL_MS)
        );

        if (bytes_read > 0) {
            transport_consume_uart_bytes(buffer, (size_t) bytes_read);
        }

        transport_poll_controller_timeout();

        if (transport_now_ms() < next_heartbeat_ms) {
            continue;
        }

        transport_send_debug("HEARTBEAT");
        next_heartbeat_ms = transport_now_ms() + UART_TRANSPORT_HEARTBEAT_MS;
    }
}

void uart_transport_start(void)
{
    controller_init(&s_transport_context.controller);
    s_transport_context.rx_line_length = 0U;

    uart_config_t config = {
        .baud_rate = UART_TRANSPORT_BAUDRATE,
        .data_bits = UART_DATA_8_BITS,
        .parity = UART_PARITY_DISABLE,
        .stop_bits = UART_STOP_BITS_1,
        .flow_ctrl = UART_HW_FLOWCTRL_DISABLE,
        .source_clk = UART_SCLK_APB,
    };

    uart_driver_install(UART_TRANSPORT_PORT, UART_TRANSPORT_BUFFER_SIZE * 2, 0, 0, NULL, 0);
    uart_param_config(UART_TRANSPORT_PORT, &config);
    uart_set_pin(UART_TRANSPORT_PORT, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE, UART_PIN_NO_CHANGE);

    xTaskCreate(transport_task, "uart_transport", 4096, NULL, 5, NULL);
}

