controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    /* Update sensor freshness flags and track last input time */
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        /* Invalid/malformed input - clear validity flags */
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No new sensor data - check for timeouts */
        /* If either sensor hasn't been seen in 1000ms, go to safe vent */
        if (now_ms - controller->last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS ||
            now_ms - controller->last_door_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* One or both sensors are stale - go to safe vent */
            controller_set_safe_vent(controller);
        } else {
            /* Sensors haven't changed, maintain current state */
            /* No action needed - keep current actuator state */
        }
        break;
    }

    /* Determine required output based on policy */
    bool need_compressor_on = false;
    bool need_vent_closed = false;

    uint32_t now_ms = input.now_ms;

    if (!controller->has_valid_door) {
        /* Door sensor is invalid or not yet valid - go to safe vent */
        controller_set_safe_vent(controller);
    } else {
        /* Door is valid - check pressure freshness and apply policy */

        /* Check if either sensor is stale (stale = hasn't been seen in 1000ms) */
        bool has_stale_sensor = false;
        if (!controller->has_valid_pressure || now_ms - controller->last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            has_stale_sensor = true;
        } else if (!controller->has_valid_door || now_ms - controller->last_door_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            has_stale_sensor = true;
        }

        if (has_stale_sensor) {
            /* Either sensor is stale - go to safe vent */
            controller_set_safe_vent(controller);
        } else {
            /* Both sensors valid and fresh - apply pressure-based policy */
            int pressure = controller->last_pressure_kpa;

            if (!controller->door_closed) {
                /* Door is open: safe vent state */
                controller_set_safe_vent(controller);
            } else {
                /* Door is closed - apply pressure-based policy */
                if (pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                    /* Low pressure: pressurize */
                    need_compressor_on = true;
                    need_vent_closed = true;
                    controller->state = CONTROLLER_STATE_PRESSURIZING;
                } else if (pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                    /* High pressure: relieve */
                    need_compressor_on = false;
                    need_vent_closed = false;
                    controller->state = CONTROLLER_STATE_RELIEVING;
                } else {
                    /* In band (40-60): hold previous safe output */
                    if (previous_state == CONTROLLER_STATE_PRESSURIZING ||
                        previous_state == CONTROLLER_STATE_RELIEVING) {
                        controller->state = previous_state;
                    } else if (previous_state == CONTROLLER_STATE_HOLDING) {
                        /* Already in holding, stay in holding */
                        controller->state = CONTROLLER_STATE_HOLDING;
                    } else {
                        /* Transition to holding from safe vent */
                        controller->state = CONTROLLER_STATE_HOLDING;
                    }
                }
            }
        }
    }

    /* Apply the required actuator state */
    if (need_compressor_on) {
        controller->compressor_on = true;
    } else {
        controller->compressor_on = false;
    }

    if (need_vent_closed) {
        controller->vent_open = false;
    } else {
        controller->vent_open = true;
    }

    /* Check for state changes */
    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);

    return output;
}

